+import { resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+/** Load the configuration files selected by a command's config options. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [getCwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  let firstPath: string | undefined;
+  let values: Record<string, unknown> = {};
+
+  for (const searchPath of paths) {
+    const file = await findConfigFile(searchPath, options.name, formats);
+    if (!file) continue;
+
+    const content = await readTextFile(file);
+    const parsed = parseConfig(content, file, options);
+    const flattened = flattenConfig(parsed);
+    firstPath ??= file;
+    // Earlier search paths take precedence when files are merged.
+    values = options.mergeConfigs ? { ...flattened, ...values } : flattened;
+    if (!options.mergeConfigs) break;
+  }
+
+  return { path: firstPath, values };
+}
+
+async function findConfigFile(
+  searchPath: string,
+  name: string,
+  formats: string[],
+): Promise<string | undefined> {
+  for (const format of formats) {
+    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+    const path = resolve(searchPath, filename);
+    try {
+      await readTextFile(path);
+      return path;
+    } catch (error) {
+      if (isNotFound(error)) continue;
+      throw error;
+    }
+  }
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  options: ConfigOptions,
+): Record<string, unknown> {
+  try {
+    const result = options.parser
+      ? options.parser(content)
+      : path.endsWith(".rc") ? parseRc(content) : JSON.parse(content);
+    if (!isPlainObject(result)) throw new TypeError("Configuration must be an object.");
+    return result;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const match = /^([^=]+?)\\s*=\\s*(?:"([^"]*)"|(.*?))\\s*$/.exec(line);
+    if (!match) throw new SyntaxError(`Invalid RC entry: ${line}`);
+    result[match[1].trim()] = match[2] ?? match[3].trim();
+  }
+  return result;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(child)) Object.assign(result, flattenConfig(child, name));
+    else result[name] = child;
+  }
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function getCwd(): string {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as typeof globalThis & { Deno?: { cwd(): string } };
+  if (Deno) return Deno.cwd();
+  return process.cwd();
+}
+
+async function readTextFile(path: string): Promise<string> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as typeof globalThis & {
+    Deno?: { readTextFile(path: string): Promise<string> };
+  };
+  if (Deno) return await Deno.readTextFile(path);
+  const { readFile } = await import("node:fs/promises");
+  return await readFile(path, "utf8");
+}
+
+function isNotFound(error: unknown): boolean {
+  return error instanceof Deno.errors.NotFound ||
+    (typeof error === "object" && error !== null && "code" in error &&
+      error.code === "ENOENT");
+}
