+} from "../../mod.ts";
+
+async function withConfig(
+  files: Record<string, string>,
+  callback: (path: string) => Promise<void>,
+) {
+  const path = await Deno.makeTempDir();
+  try {
+    await Promise.all(
+      Object.entries(files).map(([name, content]) =>
+        Deno.writeTextFile(join(path, name), content)
+      ),
+    );
+    await callback(path);
+  } finally {
+    await Deno.remove(path, { recursive: true });
+  }
+}
+
+test("[command] loads JSON config defaults and exposes their path", async () => {
+  await withConfig({ "app.json": '{"foo-bar":"config","count":0}' }, async (path) => {
+    const cmd = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [path] })
+      .option("--foo-bar <value:string>", "")
+      .option("--count <value:number>", "");
+
+    const { options } = await cmd.parse([]);
+    assertEquals(options, { fooBar: "config", count: 0 });
+    assertEquals(cmd.getConfigPath(), join(path, "app.json"));
+    assertEquals(cmd.getConfigValues(), { fooBar: "config", count: 0 });
+  });
+});
+
+test("[command] CLI and environment values override config values", async () => {
+  await withConfig({ "app.json": '{"value":"config"}' }, async (path) => {
+    const cmd = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [path] })
+      .env("VALUE=<value:string>", "")
+      .option("--value <value:string>", "");
+
+    Deno.env.set("VALUE", "environment");
+    try {
+      assertEquals((await cmd.parse([])).options, { value: "environment" });
+      assertEquals((await cmd.parse(["--value", "cli"])).options, { value: "cli" });
+    } finally {
+      Deno.env.delete("VALUE");
+    }
+  });
+});
+
+test("[command] parses RC files and combines configured paths", async () => {
