export async function stat(input: string): Promise<{ isDirectory: boolean }> {
  // dnt-shim-ignore
  const { Deno } = globalThis as any;

  if (Deno) {
    return Deno.stat(input);
  }
  const { statSync } = await import("node:fs");
  const stats = statSync(input);

  return {
    get isDirectory() {
